#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long a[55];
        for(int i=0;i<N;i++) scanf("%lld", &a[i]);
        long long ans=0;
        for(int i=0;i<N;i++){
            long long sum=0, prod=1;
            for(int j=i;j<N;j++){
                sum+=a[j];
                prod*=a[j];
                if(sum==prod) ans++;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

