const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let results = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const a = input.slice(idx, idx + N);
  idx += N;
  let ans = 0;
  for (let i = 0; i < N; i++) {
    let sum = 0;
    let prod = 1;
    for (let j = i; j < N; j++) {
      sum += a[j];
      prod *= a[j];
      if (sum === prod) ans++;
    }
  }
  results.push(String(ans));
}
console.log(results.join('\n'));
